// ============================================================================
// Event Cache
// ============================================================================
GpuRuntime::Event* getOrCreateEvent(const std::string& eventName, GpuRuntime::Device& device) {
  static std::unordered_map<std::string, std::unique_ptr<GpuRuntime::Event>> eventCache;
  auto it = eventCache.find(eventName);
  if (it == eventCache.end()) {
    // Create event via device
    auto newEvent = device.createEvent();
    if (!newEvent) return nullptr;

    auto eventPtr = newEvent.get();
    eventCache[eventName] = std::move(newEvent);
    return eventPtr;
  }
  return it->second.get();
}

// ============================================================================
// Program Cache with Persistent Disk Cache
//
// ============================================================================
struct ProgramCacheEntry {
  std::unique_ptr<GpuRuntime::Program> program;
  std::string sourceHash;  // SHA-256 of source for validation
};

// Helper: Get compiled format Kind for a backend
GpuRuntime::ProgramSource::Kind getCompiledFormatKind(const std::string& backend) {
  if (backend == "cuda") return GpuRuntime::ProgramSource::Kind::Ptx;
  if (backend == "hip") return GpuRuntime::ProgramSource::Kind::Hsaco;
  if (backend == "vulkan") return GpuRuntime::ProgramSource::Kind::Spirv;
  if (backend == "metal") return GpuRuntime::ProgramSource::Kind::Metallib;
  if (backend == "opencl") return GpuRuntime::ProgramSource::Kind::OpenClBinary;
  return GpuRuntime::ProgramSource::Kind::CudaCpp;  // fallback
}

GpuRuntime::Program* getOrCreateProgram(GpuRuntime::Device& device, const std::string& backend, const std::string& kernelName) {
  // In-memory cache (per-process)
  static std::unordered_map<std::string, ProgramCacheEntry> cache;

  // +: Load source first to compute hash for cache key validation
  // This prevents stale programs when kernel source changes within a process
  GpuRuntime::ProgramSource src;
  if (!NavatalaRegistry::tryGetKernelSource(backend, kernelName, src)) {
    return nullptr;
  }

  // Compute source hash for cache validation (include device identity to avoid
  // cross-device binary cache collisions, especially for OpenCL program binaries).
  std::string sourceStr(src.bytes.begin(), src.bytes.end());
  std::string cacheKeySource = sourceStr;
  cacheKeySource += "\nDEVICE_NAME:" + device.getName();
  cacheKeySource += "\nDEVICE_CAP:" + device.getComputeCapability();
  std::string sourceHash = GpuRuntime::computeSourceHash(cacheKeySource);

  // Include sourceHash in cache key to detect source changes
  const std::string key = backend + ":" + kernelName + ":" + sourceHash;

  // Check in-memory cache with hash validation
  auto it = cache.find(key);
  if (it != cache.end()) {
    // Defense in depth: validate hash matches before returning
    if (it->second.sourceHash == sourceHash) {
      return it->second.program.get();
    } else {
      // Hash mismatch - remove stale entry and fall through to compilation
      cache.erase(it);
    }
  }

  // Check persistent disk cache before compiling
  std::vector<std::uint8_t> cachedBytes;

  if (GpuRuntime::tryLoadFromDiskCache(backend, kernelName, cacheKeySource, cachedBytes)) {
    // Determine the appropriate kind for cached bytes using backend-specific format
    GpuRuntime::ProgramSource::Kind cachedKind = getCompiledFormatKind(backend);

    if (cachedKind != GpuRuntime::ProgramSource::Kind::CudaCpp) {  // Valid format found
      GpuRuntime::ProgramSource cachedSrc;
      cachedSrc.kind = cachedKind;
      cachedSrc.entryPoint = src.entryPoint;
      cachedSrc.bytes = cachedBytes;

      // Try to load from cached bytes
      auto cachedProg = device.createProgram(cachedSrc);
      if (cachedProg) {
        ProgramCacheEntry entry;
        entry.program = std::move(cachedProg);
        entry.sourceHash = sourceHash;
        auto [it3, _] = cache.emplace(key, std::move(entry));
        return it3->second.program.get();
      }
      // If loading from cache failed, fall through to compile
    }
  }

  // Compile from source
  auto prog = device.createProgram(src);
  if (!prog) return nullptr;

  // Save compiled program to disk cache
  // Extract compiled bytes from the program and save to persistent cache
  std::vector<std::uint8_t> compiledBytes = prog->getCompiledBytes();
  std::string compiledFormat = prog->getCompiledFormat();
  (void)compiledFormat;
  if (!compiledBytes.empty()) {
    GpuRuntime::saveToDiskCache(backend, kernelName, cacheKeySource, compiledBytes);
  }

  ProgramCacheEntry entry;
  entry.program = std::move(prog);
  entry.sourceHash = sourceHash;

  auto [it2, _] = cache.emplace(key, std::move(entry));
  return it2->second.program.get();
}

GpuRuntime::Buffer* findBuffer(const std::vector<NavatalaRegistry::NamedBuffer>& buffers, const std::string& name) {
  for (const auto& kv : buffers) {
    if (kv.first == name) return kv.second;
  }
  return nullptr;
}

GpuRuntime::Buffer* findBufferWithWorkspace(const std::vector<NavatalaRegistry::NamedBuffer>& buffers,
                                            std::unordered_map<std::string, std::unique_ptr<GpuRuntime::Buffer>>& workspace,
                                            const std::string& name) {
  if (auto* b = findBuffer(buffers, name)) return b;
  auto it = workspace.find(name);
  if (it == workspace.end()) return nullptr;
  return it->second.get();
}

// Tier-C pre-start: persist workspace pools across program invocations (per device).
struct WorkspacePoolState {
  std::vector<std::unique_ptr<GpuRuntime::Buffer>> defaultPool;
  std::unordered_map<std::string, std::vector<std::unique_ptr<GpuRuntime::Buffer>>> classPools;
};
static std::unordered_map<std::uintptr_t, WorkspacePoolState> g_workspacePools;
static WorkspacePoolState& getWorkspacePoolState(GpuRuntime::Device& device) {
  const std::uintptr_t key = reinterpret_cast<std::uintptr_t>(&device);
  return g_workspacePools[key];
}

static std::size_t evalWorkspaceSizeExpr(const std::string& expr,
                                         const std::vector<NavatalaRegistry::NamedBuffer>& buffers,
                                         std::unordered_map<std::string, std::unique_ptr<GpuRuntime::Buffer>>& workspace) {
  (void)buffers; (void)workspace;
  // Phase-3: keep this intentionally minimal. We currently emit raw byte counts as decimal strings.
  try {
    std::size_t idx = 0;
    const std::size_t v = std::stoull(expr, &idx, 10);
    if (idx != expr.size()) return 0;
    return v;
  } catch (...) {
    return 0;
  }
}

// Tier-C pre-start: simple workspace buffer pool to reduce allocation churn.
static std::unique_ptr<GpuRuntime::Buffer> acquireWorkspaceBuffer(
    GpuRuntime::Device& device, std::size_t bytes,
    std::vector<std::unique_ptr<GpuRuntime::Buffer>>& pool,
    bool reuseAtLeast) {
  if (reuseAtLeast) {
    auto best = pool.end();
    std::size_t bestBytes = std::numeric_limits<std::size_t>::max();
    for (auto it = pool.begin(); it != pool.end(); ++it) {
      if (!(*it)) continue;
      const std::size_t sz = (*it)->sizeBytes();
      if (sz >= bytes && sz < bestBytes) { best = it; bestBytes = sz; }
    }
    if (best != pool.end()) {
      auto buf = std::move(*best);
      pool.erase(best);
      return buf;
    }
  } else {
    for (auto it = pool.begin(); it != pool.end(); ++it) {
      if ((*it) && (*it)->sizeBytes() == bytes) {
        auto buf = std::move(*it);
        pool.erase(it);
        return buf;
      }
    }
  }
  // Workspace buffers must be host-mappable because some backends (and deterministic mode)
  // use host fallbacks for library ops (sort/reduce/scatter, etc.).
  return device.createBuffer(bytes, GpuRuntime::MemoryKind::Managed);
}

