static bool dispatch_navatala_StdLib_Sort_radixSortPairsU32F32(GpuRuntime::LibraryOps* lib, const std::string& backend, GpuRuntime::Device& device, GpuRuntime::Queue& queue, GpuRuntime::Buffer& keysIn, GpuRuntime::Buffer& valsIn, GpuRuntime::Buffer& count, GpuRuntime::Buffer& keysOut, GpuRuntime::Buffer& valsOut) {
#if NAVATALA_GPU_HAS_LIBRARY_OPS
  if (lib && lib->hasSortReduceSupport()) {
    const std::uint32_t n = static_cast<std::uint32_t>(std::max<std::int32_t>(0, readScalar<std::int32_t>(count)));
    GpuRuntime::SortPairsParams params;
    params.n = n;
    auto status = lib->sortRadixPairsU32(queue, params, keysIn, valsIn, keysOut, valsOut, GpuRuntime::DataType::Float32);
    if (status == GpuRuntime::LibraryStatus::Success) return true;
  }
#endif
  // Host radix-sort pairs fallback (stable) used for deterministic scatter-reduce.
  {
    queue.synchronize();
    const std::uint32_t n = static_cast<std::uint32_t>(std::max<std::int32_t>(0, readScalar<std::int32_t>(count)));
    if (keysIn.sizeBytes() < static_cast<std::size_t>(n) * sizeof(std::uint32_t)) return false;
    if (valsIn.sizeBytes() < static_cast<std::size_t>(n) * sizeof(float)) return false;
    if (keysOut.sizeBytes() < static_cast<std::size_t>(n) * sizeof(std::uint32_t)) return false;
    if (valsOut.sizeBytes() < static_cast<std::size_t>(n) * sizeof(float)) return false;
    const auto* kp = static_cast<const std::uint32_t*>(keysIn.map());
    const auto* vp = static_cast<const float*>(valsIn.map());
    struct Pair { std::uint32_t k; float v; };
    std::vector<Pair> pairs;
    pairs.reserve(n);
    for (std::uint32_t i = 0; i < n; ++i) pairs.push_back({kp[i], vp[i]});
    std::stable_sort(pairs.begin(), pairs.end(), [](const Pair& a, const Pair& b){ return a.k < b.k; });
    keysIn.unmap();
    valsIn.unmap();
    auto* kop = static_cast<std::uint32_t*>(keysOut.map());
    auto* vop = static_cast<float*>(valsOut.map());
    for (std::uint32_t i = 0; i < n; ++i) { kop[i] = pairs[i].k; vop[i] = pairs[i].v; }
    keysOut.unmap();
    valsOut.unmap();
    return true;
  }
  return false;
}

