static bool dispatch_navatala_StdLib_Reduce_reduceByKeySumF32(GpuRuntime::LibraryOps* lib, const std::string& backend, GpuRuntime::Device& device, GpuRuntime::Queue& queue, GpuRuntime::Buffer& keysIn, GpuRuntime::Buffer& valsIn, GpuRuntime::Buffer& count, GpuRuntime::Buffer& keysOut, GpuRuntime::Buffer& valsOut, GpuRuntime::Buffer& outCount) {
#if NAVATALA_GPU_HAS_LIBRARY_OPS
  if (lib && lib->hasSortReduceSupport()) {
    const std::uint32_t n = static_cast<std::uint32_t>(std::max<std::int32_t>(0, readScalar<std::int32_t>(count)));
    GpuRuntime::ReduceByKeyParams params;
    params.op = GpuRuntime::ReduceOp::Sum;
    params.n = n;
    params.numericMode = getFloat32ReduceModeFromEnv();
    auto status = lib->reduceByKeyU32(queue, params, keysIn, valsIn, keysOut, valsOut, outCount, GpuRuntime::DataType::Float32);
    if (status == GpuRuntime::LibraryStatus::Success) return true;
  }
#endif
  // Host reduce-by-key fallback used for deterministic scatter-reduce.
  {
    queue.synchronize();
    const std::uint32_t n = static_cast<std::uint32_t>(std::max<std::int32_t>(0, readScalar<std::int32_t>(count)));
    if (keysIn.sizeBytes() < static_cast<std::size_t>(n) * sizeof(std::uint32_t)) return false;
    if (valsIn.sizeBytes() < static_cast<std::size_t>(n) * sizeof(float)) return false;
    if (keysOut.sizeBytes() < static_cast<std::size_t>(n) * sizeof(std::uint32_t)) return false;
    if (valsOut.sizeBytes() < static_cast<std::size_t>(n) * sizeof(float)) return false;
    if (outCount.sizeBytes() < sizeof(std::int32_t)) return false;
    const auto* kp = static_cast<const std::uint32_t*>(keysIn.map());
    const auto* vp = static_cast<const float*>(valsIn.map());
    auto* kop = static_cast<std::uint32_t*>(keysOut.map());
    auto* vop = static_cast<float*>(valsOut.map());
    std::uint32_t outN = 0;
    if (n == 0) {
      keysIn.unmap();
      valsIn.unmap();
      keysOut.unmap();
      valsOut.unmap();
      auto* ocp = static_cast<std::int32_t*>(outCount.map());
      ocp[0] = 0;
      outCount.unmap();
      return true;
    }
    std::uint32_t i = 0;
    while (i < n) {
      // Host numeric-mode controls for Float32 Sum.
      const std::uint32_t key = kp[i];
      const auto mode = getFloat32ReduceModeFromEnv();
      double accD = 0.0;
      double cD = 0.0;
      float accF = 0.0f;
      std::uint32_t j = i;
      if (mode == GpuRuntime::ReduceNumericMode::Default) {
        while (j < n && kp[j] == key) {
          accF += vp[j];
          ++j;
        }
      } else if (mode == GpuRuntime::ReduceNumericMode::Kahan) {
        while (j < n && kp[j] == key) {
          const double v = static_cast<double>(vp[j]);
          const double y = v - cD;
          const double t = accD + y;
          cD = (t - accD) - y;
          accD = t;
          ++j;
        }
      } else if (mode == GpuRuntime::ReduceNumericMode::Pairwise || mode == GpuRuntime::ReduceNumericMode::DeterministicTree) {
        constexpr std::int64_t chunk = 1024;
        std::vector<double> partials;
        std::uint32_t jj = j;
        while (jj < n && kp[jj] == key) {
          const std::uint32_t base = jj;
          const std::uint32_t end = static_cast<std::uint32_t>(std::min<std::uint32_t>(n, base + static_cast<std::uint32_t>(chunk)));
          double s = 0.0;
          for (std::uint32_t t = base; t < end && kp[t] == key; ++t) {
            s += static_cast<double>(vp[t]);
            jj = t + 1;
          }
          partials.push_back(s);
          if (jj < n && kp[jj] != key) break;
        }
        while (partials.size() > 1) {
          std::vector<double> next; next.reserve((partials.size() + 1) / 2);
          for (std::size_t t = 0; t < partials.size(); t += 2) {
            const double a = partials[t]; const double b = (t + 1 < partials.size()) ? partials[t + 1] : 0.0; next.push_back(a + b);
          }
          partials.swap(next);
        }
        accD = partials.empty() ? 0.0 : partials[0];
        j = jj;
      } else {
        while (j < n && kp[j] == key) {
          accD += static_cast<double>(vp[j]);
          ++j;
        }
      }
      kop[outN] = key;
      vop[outN] = (mode == GpuRuntime::ReduceNumericMode::Default) ? accF : static_cast<float>(accD);
      ++outN;
      i = j;
    }
    keysIn.unmap();
    valsIn.unmap();
    keysOut.unmap();
    valsOut.unmap();
    auto* ocp = static_cast<std::int32_t*>(outCount.map());
    ocp[0] = static_cast<std::int32_t>(outN);
    outCount.unmap();
    return true;
  }
  return false;
}

