static bool dispatch_navatala_StdLib_Blas_axpyFloat32(GpuRuntime::LibraryOps* lib, const std::string& backend, GpuRuntime::Device& device, GpuRuntime::Queue& queue, GpuRuntime::Buffer& x, GpuRuntime::Buffer& y, GpuRuntime::Buffer& alpha, GpuRuntime::Buffer& out) {
#if NAVATALA_GPU_HAS_LIBRARY_OPS
  if (lib && lib->hasBlasSupport()) {
    // Out-of-place AXPY: out = alpha * x + y (implemented via memcpy(out,y) + in-place axpy).
    if (out.sizeBytes() != y.sizeBytes()) return false;
    queue.memcpy(out, y, out.sizeBytes());
    GpuRuntime::AxpyParams params;
    params.n = static_cast<std::int64_t>(x.sizeBytes() / sizeof(float));
    params.alpha = static_cast<double>(readScalar<float>(alpha));
    params.incx = 1;
    params.incy = 1;
    auto status = lib->axpy(queue, params, x, out, GpuRuntime::DataType::Float32);
    if (status == GpuRuntime::LibraryStatus::Success) return true;
  }
#endif
  // CPU fallback (no BLAS): out = y + alpha * x
  {
    queue.synchronize();
    if (out.sizeBytes() != y.sizeBytes() || x.sizeBytes() != y.sizeBytes()) return false;
    const std::int64_t n = static_cast<std::int64_t>(x.sizeBytes() / sizeof(float));
    const float a = static_cast<float>(readScalar<float>(alpha));
    auto* xp = static_cast<float*>(x.map());
    auto* yp = static_cast<float*>(y.map());
    auto* op = static_cast<float*>(out.map());
    for (std::int64_t i = 0; i < n; ++i) {
      op[i] = static_cast<float>(yp[i] + a * xp[i]);
    }
    x.unmap();
    y.unmap();
    out.unmap();
    return true;
  }
  return false;
}

