static bool dispatch_navatala_StdLib_Blas_nrm2Float32(GpuRuntime::LibraryOps* lib, const std::string& backend, GpuRuntime::Device& device, GpuRuntime::Queue& queue, GpuRuntime::Buffer& x, GpuRuntime::Buffer& result) {
#if NAVATALA_GPU_HAS_LIBRARY_OPS
  if (lib && lib->hasBlasSupport()) {
    GpuRuntime::Nrm2Params params;
    params.n = static_cast<std::int64_t>(x.sizeBytes() / sizeof(float));
    params.incx = 1;
    params.numericMode = getFloat32ReduceModeFromEnv();
      auto status = lib->nrm2(queue, params, x, result, GpuRuntime::DataType::Float32);
      if (status == GpuRuntime::LibraryStatus::Success) return true;
  }
#endif
  // CPU fallback (no BLAS): result[0] = sqrt(sum(x^2))
  {
    queue.synchronize();
    if (result.sizeBytes() < sizeof(float)) return false;
    const std::int64_t n = static_cast<std::int64_t>(x.sizeBytes() / sizeof(float));
    auto* xp = static_cast<float*>(x.map());
    const auto mode = getFloat32ReduceModeFromEnv();
    double acc = 0.0;
    if (mode == GpuRuntime::ReduceNumericMode::Default) {
      float accF = 0.0f;
      for (std::int64_t i = 0; i < n; ++i) {
        const float v = xp[i];
        accF += v * v;
      }
      acc = static_cast<double>(accF);
    } else if (mode == GpuRuntime::ReduceNumericMode::Kahan) {
      double sum = 0.0; double c = 0.0;
      for (std::int64_t i = 0; i < n; ++i) {
        const double v = static_cast<double>(xp[i]); const double term = v * v;
        const double yv = term - c; const double t = sum + yv; c = (t - sum) - yv; sum = t;
      }
      acc = sum;
    } else if (mode == GpuRuntime::ReduceNumericMode::Pairwise || mode == GpuRuntime::ReduceNumericMode::DeterministicTree) {
      constexpr std::int64_t chunk = 1024;
      std::vector<double> partials;
      partials.reserve(static_cast<std::size_t>((n + chunk - 1) / chunk));
      for (std::int64_t base = 0; base < n; base += chunk) {
        const std::int64_t end = std::min<std::int64_t>(n, base + chunk);
        double s = 0.0;
        for (std::int64_t i = base; i < end; ++i) { const double v = static_cast<double>(xp[i]); s += v * v; }
        partials.push_back(s);
      }
      while (partials.size() > 1) {
        std::vector<double> next; next.reserve((partials.size() + 1) / 2);
        for (std::size_t i = 0; i < partials.size(); i += 2) {
          const double a = partials[i]; const double b = (i + 1 < partials.size()) ? partials[i + 1] : 0.0; next.push_back(a + b);
        }
        partials.swap(next);
      }
      acc = partials.empty() ? 0.0 : partials[0];
    } else {
      for (std::int64_t i = 0; i < n; ++i) {
        const double v = static_cast<double>(xp[i]); acc += v * v;
      }
    }
    x.unmap();
    const double nrm = std::sqrt(acc);
    auto* rp = static_cast<float*>(result.map());
    rp[0] = static_cast<float>(nrm);
    result.unmap();
    return true;
  }
  return false;
}

